            width: 420mm;
            height: 297mm;
            position: relative;
            background-color: white;
            margin: 40px auto;
            overflow: hidden;
            transform: scale(0.85);
            transform-origin: top center;
            box-shadow: 0 10px 30px rgba(0,0,0,0.1);
          }
          .background-media {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            z-index: 1;
          }
          .background-image {
            width: 100%;
            height: 100%;
            background-image: url('${finalUrl}');
            background-size: contain;
            background-repeat: no-repeat;
            background-position: center;
          }
          .background-pdf {
            width: 100%;
            height: 100%;
            border: none;
          }
          .overlay-header {
            position: absolute;
            top: 10mm;
            left: 27mm;
            display: flex;
            align-items: stretch;
            z-index: 100;
            background: transparent;
            padding: 2mm 5mm;
          }
          .id-box {
            padding: 1mm 4mm;
            font-size: 26pt;
            font-weight: 900;
            color: #ea580c; 
            display: flex;
            align-items: center;
            justify-content: center;
            border-right: 2px solid #ea580c;
            margin-right: 4mm;
          }
