            <optgroup key={group.label} label={group.label}>
              {group.options.map(option => (
                <option key={option} value={option}>{option}</option>
              ))}
            </optgroup>
          ))}
        </select>
      </td>
      <td className="p-1">
        <select name="design" value={door.design} onChange={handleChange} className={`w-full border rounded px-1 py-1 h-8 ${getTailwindHighlight(isDesignHighlighted)}`}>
          {spec.designs.map(d => <option key={d} value={d}>{d}</option>)}
        </select>
      </td>
      <td className="p-1">
        <div className="flex flex-col gap-1 min-w-[70px]">
          <select name="width" value={door.width} onChange={handleChange} className={`w-full border rounded px-1 py-1 h-8 ${getTailwindHighlight(isWidthHighlighted)}`}>
            {availableWidths.map(w => <option key={w} value={w}>{w === '特寸' ? '特寸' : `${w}mm`}</option>)}
          </select>
          {door.width === '特寸' && (
            <div className="flex items-center gap-1 text-red-600 font-bold">
              <input type="number" name="customWidth" value={door.customWidth} onChange={handleChange} className="w-full border border-red-200 rounded px-1 h-6 bg-white" />
              <span className="text-[10px]">㎜</span>
            </div>
          )}
        </div>
      </td>
      <td className="p-1">
        <div className="flex flex-col gap-1 min-w-[70px]">
          <select name="height" value={door.height} onChange={handleChange} className={`w-full border rounded px-1 py-1 h-8 ${getTailwindHighlight(isHeightHighlighted)}`}>
            {availableHeights.map(h => <option key={h} value={h}>{h === '特寸' ? '特寸' : h}</option>)}
          </select>
          {door.height === '特寸' && (
            <div className="flex items-center gap-1 text-red-600 font-bold">
              <input type="number" name="customHeight" value={door.customHeight} max="2400" onChange={handleChange} className="w-full border border-red-200 rounded px-1 h-6 bg-white" />
              <span className="text-[10px]">㎜</span>
            </div>
          )}
        </div>
      </td>
      <td className="p-1 relative">
        <div className="flex items-center gap-1">
           <div className={`w-full border rounded px-1 flex flex-col justify-center overflow-hidden h-8 bg-gray-100 text-[10px] leading-[1.1] transition-colors ${getTailwindHighlight(isFrameHighlighted)}`}>
             <span className="text-gray-600 font-medium truncate">{door.frameType}</span>
             {door.isUndercut && <span className="text-red-600 font-bold truncate">アンダーカット</span>}
             {door.isFrameExtended && (
               <span className="text-red-600 font-bold truncate">
                 {door.domaExtensionType === 'none' ? '土間(伸なし)' :
                  door.domaExtensionType === 'frame' ? '土間(枠伸長)' : '土間(建具伸長)'}
               </span>
             )}
           </div>
           {canShowFrameOption && (
             <button 
               onClick={(e) => {
                 e.preventDefault();
                 setIsFrameOptionOpen(!isFrameOptionOpen);
               }}
               className={`shrink-0 w-6 h-6 rounded-full flex items-center justify-center transition-colors shadow-sm ${isFrameHighlighted ? 'bg-red-600 text-white' : 'bg-gray-200 text-gray-500 hover:bg-gray-300'}`}
               title="枠オプション設定"
             >
               <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924-1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
             </button>
           )}
        </div>

        {isFrameOptionOpen && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 text-left" onClick={() => setIsFrameOptionOpen(false)}>
            <div className="bg-white p-6 rounded-2xl shadow-2xl max-w-4xl w-full animate-in zoom-in duration-200 overflow-y-auto max-h-[90vh]" onClick={(e) => e.stopPropagation()}>
               <div className="flex justify-between items-center mb-6 border-b pb-4">
                  <div>
                    <span className="font-bold text-gray-800 text-xl">枠オプション設定</span>
                    <span className="text-gray-400 text-sm ml-4">WD{index + 1} / {door.type}</span>
                  </div>
                  <button onClick={() => setIsFrameOptionOpen(false)} className="text-gray-400 hover:text-gray-600 rounded-full p-1 hover:bg-gray-100 transition-colors">
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
               </div>

               <div className="space-y-10">
                 <section className="bg-gray-50 p-6 rounded-2xl border border-gray-100">
                    <h4 className="text-base font-bold text-gray-800 mb-4 flex items-center gap-3">
                      <input 
                        type="checkbox" 
                        name="isUndercut" 
                        checked={door.isUndercut || false} 
                        onChange={handleChange}
                        className="w-6 h-6 rounded text-red-600 focus:ring-red-500 border-2 border-gray-300" 
                      />
                      アンダーカット設定（ドア下開口）
                    </h4>
                    <div className="flex flex-col md:flex-row gap-6 items-center md:items-start ml-9">
                       <div className="w-full md:w-64 shrink-0 overflow-hidden rounded-xl border border-gray-200 shadow-sm bg-white h-40 flex items-center justify-center">
                          <img src="http://25663cc9bda9549d.main.jp/aistudio/door/kaikou.jpg" alt="ドア下開口" className="max-h-full w-auto object-contain mix-blend-multiply" />
                       </div>
                       <div className="flex-1 space-y-4">
                          <div className={`bg-white p-4 rounded-xl border-2 transition-colors ${door.isUndercut ? 'border-blue-500 bg-blue-50/30' : 'border-transparent'}`}>
                             <div className="flex flex-col">
                               <span className="text-gray-800 font-bold text-sm">アンダーカット仕様</span>
                               <span className="text-gray-400 text-[10px]">ドアを床から浮かせ、通気性を確保します</span>
                             </div>
                          </div>
                          <div className={`flex items-center gap-3 pl-2 transition-all ${door.isUndercut ? 'opacity-100' : 'opacity-30 pointer-events-none translate-x-2'}`}>
                            <span className="text-gray-600 text-xs font-bold whitespace-nowrap">隙間寸法</span>
                            <div className="flex items-center gap-2">
                               <input 
                                type="number" 
                                name="undercutHeight" 
                                value={door.undercutHeight} 
                                onChange={handleChange}
                                className="border-2 border-gray-200 rounded-lg px-3 py-2 w-28 text-right font-mono text-lg focus:border-blue-500 focus:ring-2 focus:ring-blue-200 outline-none transition-all"
                              />
                              <span className="text-gray-500 font-bold">mm</span>
                            </div>
                          </div>
                       </div>
                    </div>
                 </section>

                 <section className="bg-gray-50 p-6 rounded-2xl border border-gray-100">
                    <h4 className="text-base font-bold text-gray-800 mb-4 flex items-center gap-3">
                      <input 
                        type="checkbox" 
                        name="isFrameExtended" 
                        checked={door.isFrameExtended || false} 
                        onChange={handleChange} 
                        className="w-6 h-6 rounded text-red-600 focus:ring-red-500 border-2 border-gray-300" 
                      />
                      土間納まり設定
                    </h4>

                    <div className={`grid grid-cols-1 md:grid-cols-3 gap-6 transition-all ml-9 ${door.isFrameExtended ? 'opacity-100 scale-100' : 'opacity-30 pointer-events-none scale-[0.98]'}`}>
                      <div 
                        onClick={() => {
                          if (door.isFrameExtended) {
                            const newOptions = { ...door, domaExtensionType: 'none' as const };
                            updateDoor(door.id, { 
                              domaExtensionType: 'none', 
                              price: calculatePrice(door.type, door.design, door.height, door.customHeight, newOptions) 
                            });
                          }
                        }}
                        className={`group relative flex flex-col bg-white rounded-2xl border-2 transition-all cursor-pointer overflow-hidden ${door.domaExtensionType === 'none' ? 'border-orange-500 shadow-lg ring-4 ring-orange-50' : 'border-gray-100 hover:border-orange-200'}`}
                      >
                        <div className="h-40 bg-gray-50 flex items-center justify-center p-4 border-b">
                           <img src="http://25663cc9bda9549d.main.jp/aistudio/door/expand.jpg" alt="伸長なし" className="max-h-full w-auto object-contain mix-blend-multiply group-hover:scale-105 transition-transform duration-300" />
                        </div>
                        <div className="p-4 text-center">
                           <p className="font-bold text-gray-800 text-sm">土間納まり（伸長なし）</p>
                           <p className="text-[10px] text-gray-400 mt-1 leading-tight">標準サイズのままで<br/>土間として納めます</p>
                           <div className={`mt-3 mx-auto w-5 h-5 rounded-full border-2 flex items-center justify-center ${door.domaExtensionType === 'none' ? 'border-orange-500 bg-orange-500' : 'border-gray-200'}`}>
                             {door.domaExtensionType === 'none' && <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>}
                           </div>
                        </div>
                      </div>

                      <div 
                        onClick={() => {
                          if (door.isFrameExtended) {
                            const newOptions = { ...door, domaExtensionType: 'frame' as const };
                            updateDoor(door.id, { 
                              domaExtensionType: 'frame',
                              price: calculatePrice(door.type, door.design, door.height, door.customHeight, newOptions)
                            });
                          }
                        }}
                        className={`group relative flex flex-col bg-white rounded-2xl border-2 transition-all cursor-pointer overflow-hidden ${door.domaExtensionType === 'frame' ? 'border-orange-500 shadow-lg ring-4 ring-orange-50' : 'border-gray-100 hover:border-orange-200'}`}
                      >
                        <div className="h-40 bg-gray-50 flex items-center justify-center p-4 border-b">
                           <img src="http://25663cc9bda9549d.main.jp/aistudio/door/expandwaku.jpg" alt="枠伸長" className="max-h-full w-auto object-contain mix-blend-multiply group-hover:scale-105 transition-transform duration-300" />
                        </div>
                        <div className="p-4 text-center">
                           <p className="font-bold text-gray-800 text-sm">土間納まり（枠伸長）</p>
                           <p className="text-[10px] text-gray-400 mt-1 leading-tight">縦枠のみを下方に伸ばし<br/>埋め込み等に対応します</p>
                           <div className="mt-3 flex items-center justify-center gap-2">
                             <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${door.domaExtensionType === 'frame' ? 'border-orange-500 bg-orange-500' : 'border-gray-200'}`}>
                               {door.domaExtensionType === 'frame' && <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>}
                             </div>
                           </div>
                           {door.domaExtensionType === 'frame' && (
                             <div className="mt-3 pt-3 border-t flex items-center justify-center gap-1 animate-in slide-in-from-top-1">
                               <input 
                                 type="number" 
                                 name="frameExtensionHeight" 
                                 value={door.frameExtensionHeight} 
                                 onClick={(e) => e.stopPropagation()}
                                 onChange={handleChange} 
                                 placeholder="寸法"
                                 className="border-2 border-orange-200 rounded px-2 py-1 w-20 text-right font-mono font-bold text-orange-600 focus:border-orange-500 focus:ring-0 outline-none" 
                               />
                               <span className="text-[10px] font-bold text-gray-500">㎜</span>
                             </div>
                           )}
                        </div>
                      </div>

                      <div 
                        onClick={() => {
                          if (door.isFrameExtended) {
                            const newOptions = { ...door, domaExtensionType: 'door' as const };
                            updateDoor(door.id, { 
                              domaExtensionType: 'door',
                              price: calculatePrice(door.type, door.design, door.height, door.customHeight, newOptions)
                            });
                          }
                        }}
                        className={`group relative flex flex-col bg-white rounded-2xl border-2 transition-all cursor-pointer overflow-hidden ${door.domaExtensionType === 'door' ? 'border-orange-500 shadow-lg ring-4 ring-orange-50' : 'border-gray-100 hover:border-orange-200'}`}
                      >
                        <div className="h-40 bg-gray-50 flex items-center justify-center p-4 border-b">
                           <img src="http://25663cc9bda9549d.main.jp/aistudio/door/expanddoor.JPG" alt="建具伸長" className="max-h-full w-auto object-contain mix-blend-multiply group-hover:scale-105 transition-transform duration-300" />
                        </div>
                        <div className="p-4 text-center">
                           <p className="font-bold text-gray-800 text-sm">土間納まり（建具伸長）</p>
                           <p className="text-[10px] text-gray-400 mt-1 leading-tight">扉本体だけを下方に伸ばし<br/>段差を解消します</p>
                           <div className="mt-3 flex items-center justify-center gap-2">
                             <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${door.domaExtensionType === 'door' ? 'border-orange-500 bg-orange-500' : 'border-gray-200'}`}>
                               {door.domaExtensionType === 'door' && <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>}
                             </div>
                           </div>
                           {door.domaExtensionType === 'door' && (
                             <div className="mt-3 pt-3 border-t flex items-center justify-center gap-1 animate-in slide-in-from-top-1">
                               <input 
                                 type="number" 
                                 name="frameExtensionHeight" 
                                 value={door.frameExtensionHeight} 
                                 onClick={(e) => e.stopPropagation()}
                                 onChange={handleChange} 
                                 placeholder="寸法"
                                 className="border-2 border-orange-200 rounded px-2 py-1 w-20 text-right font-mono font-bold text-orange-600 focus:border-orange-500 focus:ring-0 outline-none" 
                               />
                               <span className="text-[10px] font-bold text-gray-500">㎜</span>
                             </div>
                           )}
                        </div>
                      </div>
                    </div>
                 </section>
               </div>

               <div className="mt-10 flex justify-end">
                  <button onClick={() => setIsFrameOptionOpen(false)} className="bg-blue-600 hover:bg-blue-700 text-white px-12 py-3.5 rounded-xl text-base font-bold transition-all shadow-xl active:scale-95">設定を保存して閉じる</button>
               </div>
            </div>
          </div>
        )}
      </td>
      <td className="p-1">
        <select name="hangingSide" value={door.hangingSide} onChange={handleChange} className="w-full border rounded px-1 py-1 h-8">
          {spec.hangingSides.map(s => <option key={s} value={s}>{s}</option>)}
        </select>
      </td>
      <td className="p-1">
        <select name="doorColor" value={door.doorColor} onChange={handleChange} className={`w-full border rounded px-1 py-1 h-8 ${getTailwindHighlight(isDoorColorHighlighted)}`}>
          {COLORS.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
      </td>
      <td className="p-1">
        <select name="frameColor" value={door.frameColor} onChange={handleChange} className={`w-full border rounded px-1 py-1 h-8 ${getTailwindHighlight(isFrameColorHighlighted)}`}>
          {COLORS.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
      </td>
      <td className="p-1">
        <div className="flex items-center gap-1">
          <select
            name="handleColor"
            value={door.handleColor}
            onChange={handleChange}
            disabled={isFoldingOrStorage}
            className={`w-full border rounded px-1 py-1 h-8 ${getTailwindHighlight(isHandleColorHighlighted)} ${isFoldingOrStorage ? 'bg-gray-50' : ''}`}
          >
            {getAvailableHandleColors().map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          {door.handleColor === "J型取手" && (
            <button
              onClick={(e) => { e.preventDefault(); onShowHandleImage(); }}
              className="no-print bg-blue-500 hover:bg-blue-400 text-white rounded-full w-4 h-4 flex items-center justify-center text-[10px] transition-colors shadow-sm shrink-0"
              title="ハンドルの写真を表示"
            >
              i
            </button>
          )}
        </div>
      </td>
      <td className="p-1 text-right font-mono font-bold text-base pr-2 text-gray-900 border-l border-gray-100">
        {door.price.toLocaleString()}
      </td>
      <td className="p-1 text-center no-print relative">
        <div className="flex items-center justify-center gap-2 whitespace-nowrap">
          <button 
            onClick={(e) => { e.preventDefault(); handleOpenDetails(); }}
            className="bg-blue-600 hover:bg-blue-700 text-white px-2 py-1 rounded text-[10px] font-bold flex items-center gap-1 transition-all active:scale-95 shadow-sm whitespace-nowrap"
            title="詳細図面にWD番号を合成して表示・印刷"
          >
            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" />
            </svg>
            詳細図
          </button>
          <button onClick={() => removeDoor(door.id)} className="text-red-500 hover:text-red-700 p-1 transition-colors shrink-0" title="行を削除">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
          </button>
        </div>
      </td>
    </tr>
  );
};

import React, { useState, useMemo, useCallback, useEffect } from 'react';
/* UsageLocationを追加 */
import { DoorItem, OrderState, DoorType, EntranceStorage, BaseboardItem, PriceRecord, StorageTypeRecord, ShippingFeeRecord, UsageLocation } from './types';
import { DoorRow } from './components/DoorRow';
import { EntranceStorageSection } from './components/EntranceStorageSection';
import { BusinessDatePicker } from './components/BusinessDatePicker';
import { DataViewerModal } from './components/DataViewerModal';
import { COLORS, HANDLE_COLORS, DOOR_SPEC_MASTER, getFrameType, HINGED_HANDLES, SLIDING_HANDLES, DOOR_POINTS, getStoragePoints, getBaseboardPoints, resolveDoorDrawingUrl, getStorageDetailPdfUrl } from './constants';
import { supabase } from './supabase';

const SIMPLE_HANDLE_OPTIONS = ["セラミックホワイト", "マットブラック", "サテンニッケル"];
const PB_OPTIONS = ["9.5", "12.5", "15.0"];

const generateId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return Math.random().toString(36).substring(2) + Date.now().toString(36);
};

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [priceList, setPriceList] = useState<PriceRecord[]>([]);
  const [storageTypes, setStorageTypes] = useState<StorageTypeRecord[]>([]);
  const [shippingFees, setShippingFees] = useState<ShippingFeeRecord[]>([]);

  const [isModalOpen, setIsModalOpen] = useState(true);
  const [isInfoModalOpen, setIsInfoModalOpen] = useState(false);
  const [isWakuModalOpen, setIsWakuModalOpen] = useState(false);
  const [isHabakiModalOpen, setIsHabakiModalOpen] = useState(false);
  const [isCornerHabakiModalOpen, setIsCornerHabakiModalOpen] = useState(false);
  const [isHandleModalOpen, setIsHandleModalOpen] = useState(false);
  const [isHardwareModalOpen, setIsHardwareModalOpen] = useState(false);
  const [isColorModalOpen, setIsColorModalOpen] = useState(false);
  const [isEstimateModalOpen, setIsEstimateModalOpen] = useState(false);
  const [isOrderFlowModalOpen, setIsOrderFlowModalOpen] = useState(false);
  const [isMailModalOpen, setIsMailModalOpen] = useState(false);
  const [isEstimateSaved, setIsEstimateSaved] = useState(false);
  const [isPbModalOpen, setIsPbModalOpen] = useState(false);
  const [isDataViewerOpen, setIsDataViewerOpen] = useState(false);

  const [isStorageGuideOpen, setIsStorageGuideOpen] = useState(true);
  const [isBaseboardGuideOpen, setIsBaseboardGuideOpen] = useState(true);

  const [isValidationModalOpen, setIsValidationModalOpen] = useState(false);
  const [validationData, setValidationData] = useState<{
    errors: string[],
    warnings: string[]
  }>({ errors: [], warnings: [] });

  const [initialSettings, setInitialSettings] = useState({
    company: '',
    siteName: '',
    contactName: '',
    phone: '',
    defaultHeight: 'H2200',
    defaultDoorColor: COLORS[0],
    defaultHandleColor: SIMPLE_HANDLE_OPTIONS[0],
    defaultBaseboardColor: COLORS[0],
  });

  const [order, setOrder] = useState<OrderState>({
    customerInfo: {
      company: '',
      address: '',
      siteName: '',
      contactName: '',
      phone: '',
      deliveryDate1: '',
      deliveryDate2: '',
      delivery1Selection: { baseboard: false, storage: false },
      delivery2Selection: { baseboard: false, storage: false },
      ceilingPB: '12.5',
    },
    doors: [],
    storage: {
      type: 'NONE',
      size: 'なし',
      color: COLORS[0],
      basePrice: 0,
      baseRing: 'なし',
      baseRingPrice: 0,
      filler: 'なし',
      fillerPrice: 0,
      fillerCount: 0,
      mirror: 'なし',
      mirrorPrice: 0,
    },
    baseboards: [
      { product: 'スリム巾木(t5.5×H23×L3960)', color: COLORS[0], unitPrice: 900, quantity: 0, unit: '本' },
      { product: 'スリムコーナー巾木', color: COLORS[0], unitPrice: 500, quantity: 0, unit: '個' },
    ],
    shipping: 0,
    memo: '',
  });

  const [addressPart, setAddressPart] = useState({
    prefecture: '',
    detail: ''
  });

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const { data: doorsData, error: doorsError } = await supabase.from('internal_doors').select('*');
        if (doorsError) throw doorsError;
        const mappedDoors: PriceRecord[] = (doorsData || []).map(d => ({
          id: d.id,
          type: d.type,
          location: d.location as UsageLocation,
          design: d.design,
          notes: '',
          height: d.height,
          framePrice: d.frame_price,
          doorPrice: d.door_price,
          setPrice: d.set_price,
          imageUrl: d.image_url
        }));
        setPriceList(mappedDoors);

        const { data: storageData, error: storageError } = await supabase.from('entrance_storages').select('*');
        if (storageError) throw storageError;
        const mappedStorage: StorageTypeRecord[] = (storageData || []).map(s => ({
          id: s.id,
          name: s.name,
          category: s.category,
          width: s.width,
          price: s.price,
          imageUrl: s.image_url
        }));
        if (!mappedStorage.find(s => s.id === 'NONE')) {
          mappedStorage.unshift({ id: "NONE", name: "なし", category: "なし", width: 0, price: 0 });
        }
        setStorageTypes(mappedStorage);

        const { data: shippingData, error: shippingError } = await supabase.from('shipping_fees').select('*').order('id');
        if (shippingError) throw shippingError;
        setShippingFees(shippingData as ShippingFeeRecord[]);

      } catch (error) {
        console.error('Error fetching data:', error);
        alert('データの取得に失敗しました。');
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  useEffect(() => {
    if (shippingFees.length === 0) return;
    const address = order.customerInfo.address;
    let matchedFee = 0;
    let longestMatch = -1;

    shippingFees.forEach(fee => {
        if (address.startsWith(fee.prefecture)) {
            if (fee.prefecture.length > longestMatch) {
                longestMatch = fee.prefecture.length;
                matchedFee = fee.price;
            }
        }
    });

    setOrder(prev => {
        if (prev.shipping === matchedFee) return prev;
        return { ...prev, shipping: matchedFee };
    });
  }, [shippingFees, order.customerInfo.address]);

  const resolveHandleName = (simpleName: string, doorType: string) => {
    if (doorType.includes("折戸") || doorType.includes("物入")) return "J型取手";
    const isSliding = doorType.includes("引") || doorType.includes("引き");
    const list = isSliding ? SLIDING_HANDLES : HINGED_HANDLES;
    return list.find(h => h.includes(simpleName)) || list[0];
  };

  const handleStart = () => {
    const defaultType = DoorType.Hinged;
    const defaultSpec = DOOR_SPEC_MASTER[defaultType];
    const defaultDesign = defaultSpec.designs[0]; 
    const initialPrice = priceList.find(p => p.type === defaultType && p.height === initialSettings.defaultHeight && p.design === defaultDesign)?.setPrice || 27300;

    setOrder(prev => ({
      ...prev,
      customerInfo: { 
        ...prev.customerInfo, 
        company: initialSettings.company, 
        siteName: initialSettings.siteName, 
        contactName: initialSettings.contactName,
        phone: initialSettings.phone
      },
      storage: { ...prev.storage, color: initialSettings.defaultDoorColor },
      baseboards: prev.baseboards.map(b => ({ ...b, color: initialSettings.defaultBaseboardColor })),
      doors: [{
        id: generateId(),
        roomName: 'LDK',
        type: defaultType,
        design: defaultDesign,
        width: '778',
        height: initialSettings.defaultHeight,
        frameType: getFrameType(defaultType, initialSettings.defaultHeight),
        hangingSide: '右吊元(R)',
        doorColor: initialSettings.defaultDoorColor,
        frameColor: initialSettings.defaultDoorColor,
        handleColor: resolveHandleName(initialSettings.defaultHandleColor, defaultType),
        specialNotes: '',
        price: initialPrice,
        isUndercut: false,
        undercutHeight: 120,
        isFrameExtended: false,
        frameExtensionHeight: 130,
      }]
    }));
    setIsModalOpen(false);
  };

  const addDoorRow = () => {
    const defaultType = DoorType.Hinged;
    const defaultSpec = DOOR_SPEC_MASTER[defaultType];
    const defaultDesign = defaultSpec.designs[0];
    const initialPrice = priceList.find(p => p.type === defaultType && p.height === initialSettings.defaultHeight && p.design === defaultDesign)?.setPrice || 27300;

    setOrder(prev => ({
      ...prev,
      doors: [...prev.doors, {
        id: generateId(),
        roomName: '',
        type: defaultType,
        design: defaultDesign,
        width: '778', 
        height: initialSettings.defaultHeight,
        frameType: getFrameType(defaultType, initialSettings.defaultHeight),
        hangingSide: 'なし',
        doorColor: initialSettings.defaultDoorColor,
        frameColor: initialSettings.defaultDoorColor,
        handleColor: resolveHandleName(initialSettings.defaultHandleColor, defaultType),
        specialNotes: '',
        price: initialPrice,
        isUndercut: false,
        undercutHeight: 120,
        isFrameExtended: false,
        frameExtensionHeight: 130,
      }]
    }));
  };

  const updateDoor = useCallback((id: string, updates: Partial<DoorItem>) => {
    setOrder(prev => ({ ...prev, doors: prev.doors.map(d => d.id === id ? { ...d, ...updates } : d) }));
  }, []);

  const removeDoor = useCallback((id: string) => {
    if (window.confirm('このWD行を削除してもよろしいですか？')) {
      setOrder(prev => ({ ...prev, doors: prev.doors.filter(d => d.id !== id) }));
    }
  }, []);

  const handlePrefectureChange = (pref: string) => {
    setAddressPart(prev => {
      const newState = { ...prev, prefecture: pref };
      setOrder(o => ({ ...o, customerInfo: { ...o.customerInfo, address: `${newState.prefecture}${newState.detail}` } }));
      return newState;
    });
  };

  const handleAddressDetailChange = (detail: string) => {
    setAddressPart(prev => {
      const newState = { ...prev, detail };
      setOrder(o => ({ ...o, customerInfo: { ...o.customerInfo, address: `${newState.prefecture}${newState.detail}` } }));
      return newState;
    });
  };

  const handleUpdateShipping = (id: number, newPrice: number) => {
    setShippingFees(prev => prev.map(item => item.id === id ? { ...item, price: newPrice } : item));
  };

  const handleDeliveryItemChange = (dateNum: 1 | 2, item: 'baseboard' | 'storage', checked: boolean) => {
    setOrder(prev => {
      const newInfo = { ...prev.customerInfo };
      if (dateNum === 1) {
        newInfo.delivery1Selection = { ...newInfo.delivery1Selection, [item]: checked };
        if (checked) {
          newInfo.delivery2Selection = { ...newInfo.delivery2Selection, [item]: false };
        }
      } else {
        newInfo.delivery2Selection = { ...newInfo.delivery2Selection, [item]: checked };
        if (checked) {
          newInfo.delivery1Selection = { ...newInfo.delivery1Selection, [item]: false };
        }
      }
      return { ...prev, customerInfo: newInfo };
    });
  };

  const totals = useMemo(() => {
    const doorPoints = order.doors.reduce((sum, d) => sum + (DOOR_POINTS[d.type] || 0), 0);
    const storagePoints = getStoragePoints(order.storage.type);
    const totalBaseboardQty = order.baseboards.reduce((sum, b) => b.unit === '本' ? sum + b.quantity : sum, 0);
    const baseboardPoints = getBaseboardPoints(totalBaseboardQty);

    const totalPoints = doorPoints + storagePoints + baseboardPoints;

    const baseShipping = order.shipping;
    const finalShipping = totalPoints >= 10 ? baseShipping : Math.floor(baseShipping * (totalPoints / 10));

    const doorSubtotal = order.doors.reduce((sum, d) => sum + d.price, 0);
    const storageSubtotal = order.storage.type === 'NONE' ? 0 : order.storage.basePrice + order.storage.baseRingPrice + (order.storage.fillerPrice * order.storage.fillerCount) + order.storage.mirrorPrice;
    const baseboardSubtotal = order.baseboards.reduce((sum, b) => sum + (b.unitPrice * b.quantity), 0);

    const subtotal = doorSubtotal + storageSubtotal + baseboardSubtotal + finalShipping;
    const tax = Math.floor(subtotal * 0.1);
    const total = subtotal + tax;

    return { 
      doorSubtotal, 
      storageSubtotal, 
      baseboardSubtotal, 
      subtotal, 
      tax, 
      total, 
      totalPoints, 
      finalShipping,
      isShippingDiscounted: totalPoints > 0 && totalPoints < 10
    };
  }, [order]);

  const hasStorage = useMemo(() => order.storage.type !== 'NONE', [order.storage.type]);
  const hasBaseboard = useMemo(() => order.baseboards.reduce((sum, b) => sum + b.quantity, 0) > 0, [order.baseboards]);

  const isStorageDateSelected = order.customerInfo.delivery1Selection.storage || order.customerInfo.delivery2Selection.storage;
  const isBaseboardDateSelected = order.customerInfo.delivery1Selection.baseboard || order.customerInfo.delivery2Selection.baseboard;

  const showStorageBubble = hasStorage && !isStorageDateSelected && isStorageGuideOpen;
  const showBaseboardBubble = hasBaseboard && !isBaseboardDateSelected && isBaseboardGuideOpen;

  const validateOrder = () => {
    const errors: string[] = [];
    const warnings: string[] = [];
    const basicFields = [
      { key: 'company', label: '会社名' },
      { key: 'siteName', label: '現場名' },
      { key: 'contactName', label: 'ご担当者名' },
      { key: 'address', label: '納品先住所' },
    ];
    basicFields.forEach(f => { if (!order.customerInfo[f.key as keyof typeof order.customerInfo]) errors.push(`${f.label}が入力されていません。`); });

    if (!order.customerInfo.deliveryDate1 && !order.customerInfo.deliveryDate2) {
      errors.push('納品希望日が入力されていません。');
    }

    if (hasBaseboard && !order.customerInfo.delivery1Selection.baseboard && !order.customerInfo.delivery2Selection.baseboard) {
      errors.push('巾木の納品希望日（①または②）が選択されていません。');
      setIsBaseboardGuideOpen(true);
    }
    if (hasStorage && !order.customerInfo.delivery1Selection.storage && !order.customerInfo.delivery2Selection.storage) {
      errors.push('玄関収納の納品希望日（①または②）が選択されていません。');
      setIsStorageGuideOpen(true);
    }

    if (order.shipping === 0) {
      errors.push('送料が計算できません。納品先住所（都道府県）を確認してください。');
    }

    if (order.doors.length === 0 && order.storage.type === 'NONE') errors.push('商品を選択してください。');

    return { errors, warnings };
  };

  const handleOpenEstimate = () => {
    const { errors, warnings } = validateOrder();
    if (errors.length > 0 || warnings.length > 0) {
      setValidationData({ errors, warnings });
      setIsValidationModalOpen(true);
      return;
    }
    setIsEstimateModalOpen(true);
  };

  /**
   * 詳細図面を一括で出力するハンドラ
   */
  const handleBatchExport = () => {
    const { errors } = validateOrder();
    if (errors.length > 0) {
      setValidationData({ errors, warnings: [] });
      setIsValidationModalOpen(true);
      return;
    }

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
      alert('ポップアップがブロックされました。ブラウザの設定を確認してください。');
      return;
    }

    let pagesHtml = '';

    // 内部建具のページ生成
    order.doors.forEach((door, index) => {
      const finalUrl = resolveDoorDrawingUrl(door, priceList);
      const isPdf = finalUrl.toLowerCase().endsWith('.pdf');
      const wdText = `WD-${index + 1}`;

      const widthHtml = door.width === '特寸' ? `<span style="color: #ef4444; font-weight: bold;">${door.customWidth}㎜特寸</span>` : `${door.width}`;
      const heightHtml = door.height === '特寸' ? `<span style="color: #ef4444; font-weight: bold;">${door.customHeight}㎜特寸</span>` : `${door.height.replace('H', '')}`;

      const frameOptionText = [];
      if (door.isUndercut) frameOptionText.push(`アンダーカット${door.undercutHeight}㎜`);
      if (door.isFrameExtended) {
        if (door.domaExtensionType === 'none') frameOptionText.push('土間(伸なし)');
        else if (door.domaExtensionType === 'frame') frameOptionText.push(`土間(枠+${door.frameExtensionHeight})`);
        else if (door.domaExtensionType === 'door') frameOptionText.push(`土間(扉+${door.frameExtensionHeight})`);
      }
      const frameOptionHtml = frameOptionText.length > 0 
        ? `<span style="color: #ef4444; font-weight: bold; margin-left: 0.5em;">(${frameOptionText.join('/')})</span>` 
        : '';

      pagesHtml += `
        <div class="page-container">
          <div class="background-media">
            ${isPdf 
              ? `<iframe src="${finalUrl}#toolbar=0&navpanes=0&scrollbar=0&view=FitH" class="background-pdf"></iframe>`
              : `<div class="background-image" style="background-image: url('${finalUrl}')"></div>`
            }
          </div>
          <div class="overlay-header">
            <div class="wd-box">${wdText}</div>
            <div class="details-box">
              <div class="details-row">
                <div class="details-item"><span class="details-label">物件名</span><span class="details-value">${order.customerInfo.siteName}</span></div>
                <div class="details-item"><span class="details-label">部屋名</span><span class="details-value">${door.roomName}</span></div>
                <div class="details-item"><span class="details-label">種類</span><span class="details-value">${door.type}</span></div>
                <div class="details-item"><span class="details-label">デザイン</span><span class="details-value">${door.design}</span></div>
                <div class="details-item"><span class="details-label">サイズ</span><span class="details-value">${widthHtml}×${heightHtml}</span></div>
              </div>
              <div class="details-row">
                <div class="details-item"><span class="details-label">枠仕様</span><span class="details-value">${door.frameType}${frameOptionHtml}</span></div>
                <div class="details-item"><span class="details-label">吊元</span><span class="details-value">${door.hangingSide}</span></div>
                <div class="details-item"><span class="details-label">色</span><span class="details-value">${door.doorColor}(枠:${door.frameColor})</span></div>
                <div class="details-item"><span class="details-label">ハンドル</span><span class="details-value">${door.handleColor}</span></div>
              </div>
            </div>
          </div>
        </div>
      `;
    });

    // 玄関収納のページ生成
    if (order.storage.type !== 'NONE') {
      const storageRecord = storageTypes.find(s => s.id === order.storage.type);
      const finalUrl = (storageRecord && storageRecord.imageUrl) ? storageRecord.imageUrl : getStorageDetailPdfUrl(order.storage.type);
      const isPdf = finalUrl.toLowerCase().endsWith('.pdf');
